    REACTION_REGISTER_THREAD();

    // 1. Create two TestObserver instances
    auto target = std::make_shared<TestObserver>(targetName);
    auto observer = std::make_shared<TestObserver>(observerName);

    // 2. Get the singleton ObserverGraph instance
    auto& graph = reaction::ObserverGraph::getInstance();

    // 3. Add observer relationship between target and observer
    graph.addObserver(target, observer);

    // 4. Notify target of change
    target->valueChanged(true);

    // 5. Check if observer was notified and get call count
    bool notified = observer->wasChanged();
    int callCount = observer->getCallCount();

    // 6. Return the results
    return std::make_pair(notified, callCount);
}

}  // namespace test_reaction
