#pragma once

#include <reaction/memory/memory_config.h>
#include <reaction/memory/stack_monitor.h>

namespace test_reaction {

struct StackLimitSnapshot {
    reaction::memory::StackMonitor::UsageStats statsBeforeGuard;
    reaction::memory::StackMonitor::UsageStats statsAfterGuard;
    bool templateAllocationAllowed;
    bool runtimeAllocationAllowed;
    bool guardHeld;
    bool allocationBlockedWhileGuardHeld;
};

StackLimitSnapshot test_stack_monitor_limits() {
    // 1. Enable monitoring
    reaction::memory::StackMonitor::enableMonitoring();

    // 2. Initialize stack monitor
    reaction::memory::StackMonitor::initialize();

    // 3. Get usage statistics before guard
    StackLimitSnapshot snapshot;
    snapshot.statsBeforeGuard = reaction::memory::StackMonitor::getStats();

    // 4. Check if template allocation is allowed
    constexpr size_t LargeSize = 64; // Using MAX_SBO_SIZE as large size
    snapshot.templateAllocationAllowed = reaction::memory::StackMonitor::canAllocate<LargeSize>();

    // 5. Check if runtime allocation is allowed
    snapshot.runtimeAllocationAllowed = reaction::memory::StackMonitor::canAllocate(1);

    // 6. Create large StackGuard instance
    reaction::memory::StackGuard<LargeSize> guard;

    // 7. Check if guard succeeded
    snapshot.guardHeld = guard.success();

    // 8. Check if allocation blocked while guard is held
    snapshot.allocationBlockedWhileGuardHeld = reaction::memory::StackMonitor::wasAllocationBlocked();

    // 9. Get usage statistics after guard
    snapshot.statsAfterGuard = reaction::memory::StackMonitor::getStats();

    // 10. Return stack limit snapshot
    return snapshot;
}

}  // namespace test_reaction
```

**Explanation:**

1. **Enable Monitoring**: `reaction::memory::StackMonitor::enableMonitoring()` turns on stack usage tracking
2. **Initialize Monitor**: `reaction::memory::StackMonitor::initialize()` sets up the initial state
3. **Pre-Guard Stats**: `reaction::memory::StackMonitor::getStats()` captures baseline usage
4. **Template Allocation Check**: `reaction::memory::StackMonitor::canAllocate<LargeSize>()` tests if a large allocation is permitted
5. **Runtime Allocation Check**: `reaction::memory::StackMonitor::canAllocate(1)` tests small allocation permission
6. **Create StackGuard**: `reaction::memory::StackGuard<LargeSize> guard` creates a guard for the large allocation
7. **Guard Success Check**: `guard.success()` verifies if the guard was able to allocate
8. **Allocation Blocking Check**: `reaction::memory::StackMonitor::wasAllocationBlocked()` detects if any allocations failed during guard lifetime
9. **Post-Guard Stats**: `reaction::memory::StackMonitor::getStats()` captures usage after guard creation
10. **Return Snapshot**: The struct contains all collected data for analysis

The implementation follows the exact sequence specified in the assessment objectives and uses the appropriate functions from the reaction library as documented in the reference materials.

